---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/registry/bejamas-maia/lib/utils";
import {
  InputGroup,
  InputGroupInput,
  InputGroupAddon,
  InputGroupButton,
} from "../input-group";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends Omit<HTMLAttributes<"input">, "size"> {
  class?: string;
  size?: "sm" | "default" | "lg";
  placeholder?: string;
  disabled?: boolean;
  showTrigger?: boolean;
  showClear?: boolean;
}

const {
  class: className = "",
  size = "default",
  placeholder,
  disabled = false,
  showTrigger = true,
  showClear = false,
  ...rest
} = Astro.props as Props;
---

<InputGroup size={size} class={cn("w-auto", className)}>
  <InputGroupInput
    data-input-group-control
    data-slot="combobox-input"
    placeholder={placeholder}
    disabled={disabled}
    autocomplete="off"
    {...rest}
   class="cn-combobox-input" />
  {
    (showTrigger || showClear) && (
      <InputGroupAddon align="inline-end">
        {showClear && (
          <InputGroupButton
            data-slot="combobox-clear"
            type="button"
            size="icon-xs"
            class="cn-combobox-clear hidden [[data-value]_&]:inline-flex"
            aria-label="Clear selection"
          >
            <SemanticIcon name="x" class="size-3.5 group-data-[size=sm]/input-group:size-3" />
          </InputGroupButton>
        )}
        {showTrigger && (
          <InputGroupButton
            data-slot="combobox-trigger"
            type="button"
            size="icon-xs"
            tabindex={-1}
            disabled={disabled}
            class={cn("cn-combobox-trigger", 
              "text-muted-foreground",
              showClear && "[[data-value]_&]:hidden",
            )}
            aria-label="Toggle menu"
          >
            <SemanticIcon
              name="chevron-down"
              data-slot="combobox-icon"
              class="cn-combobox-icon size-4 group-data-[size=sm]/input-group:size-3.5"
            />
          </InputGroupButton>
        )}
      </InputGroupAddon>
    )
  }
</InputGroup>

---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/registry/bejamas-maia/lib/utils";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"div"> {
  value: string;
  label?: string;
  disabled?: boolean;
  class?: string;
}

const {
  value,
  label,
  disabled = false,
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<div
  {...rest}
  data-slot="combobox-item"
  data-value={value}
  data-label={label}
  data-disabled={disabled ? "" : undefined}
  class={cn(
    "cn-combobox-item relative flex w-full cursor-default items-center outline-hidden select-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
    className,
  )}
>
  <span
    data-slot="combobox-item-indicator"
    class="cn-combobox-item-indicator"
  >
    <SemanticIcon
      name="check"
      class="cn-combobox-item-indicator-icon pointer-events-none"
    />
  </span>
  <span data-slot="combobox-item-text" class="cn-combobox-item-text"><slot /></span>
</div>

